		.section as16code

binop	.macro
		lda		AXLeft
		\1 		AXRight
		sta 	AXLeft
		lda		AXLeft+1
		\1 		AXRight+1
		sta 	AXLeft+1
		clc 								; no error.
		.endm

; ************************************************************************************************
;
;							Calculate Left :=  Left + Right
;
; ************************************************************************************************

AXBinaryAdd: ;; [+]
		clc
		.binop 	adc
		rts

; ************************************************************************************************
;
;							Calculate Left :=  Left - Right
;
; ************************************************************************************************

AXBinarySub: ;; [-]
		sec
		.binop 	sbc
		rts

; ************************************************************************************************
;
;							Calculate Left :=  Left AND Right
;
; ************************************************************************************************

AXBinaryAnd: ;; [&]
		.binop 	and
		rts


; ************************************************************************************************
;
;							Calculate Left :=  Left OR Right
;
; ************************************************************************************************

AXBinaryOra: ;; [|]
		.binop 	ora
		rts

; ************************************************************************************************
;
;							Calculate Left :=  Left AND Right
;
; ************************************************************************************************

AXBinaryEor: ;; [^]
		.binop 	eor
		rts

; ************************************************************************************************
;
;							Calculate Left :=  Left <> Right
;
; ************************************************************************************************

AXBinaryNotEqual: ;; [#]
		jsr 	AXBinaryEor
		lda 	AXLeft
		eor 	AXLeft+1
		beq 	_AXBEExit
		dec 	AXLeft
		dec 	AXLeft+1
_AXBEExit:
		clc
		rts

; ************************************************************************************************
;
;							Calculate Left :=  Left = Right
;
; ************************************************************************************************

AXBinaryEqual: ;; [=]
		jsr 	AXBinaryNotEqual
		lda 	AXLeft
		eor 	#$FF
		sta 	AXLeft
		sta 	AXLeft+1
		clc
		rts

		.send as16code

